<script setup lang="ts">import AppLayout from '@/layouts/AppLayout.vue'; import { useForm } from '@inertiajs/vue3'; import { route } from 'ziggy-js'; const p=defineProps<{supplier?:any;controlAccounts:any[];resultAccounts:any[]}>(); const f=useForm({name:p.supplier?.name??'',document:p.supplier?.document??'',payable_account_id:p.supplier?.payable_account_id??'',default_expense_account_id:p.supplier?.default_expense_account_id??'',active:p.supplier?.active??true}); function submit(){p.supplier?f.put(route('suppliers.update',p.supplier.id)):f.post(route('suppliers.store'))}</script>
<template><AppLayout :title="supplier?'Editar fornecedor':'Novo fornecedor'"><form class="mx-auto max-w-2xl space-y-4 p-6" @submit.prevent="submit"><h1 class="text-2xl font-bold text-white">{{ supplier?'Editar fornecedor':'Novo fornecedor' }}</h1><input v-model="f.name" placeholder="Nome" class="w-full rounded bg-black p-3 text-white"><input v-model="f.document" placeholder="Documento (opcional)" class="w-full rounded bg-black p-3 text-white"><select v-model="f.payable_account_id" class="w-full rounded bg-black p-3 text-white"><option value="">Conta de controle</option><option v-for="a in controlAccounts" :key="a.id" :value="a.id">{{a.code}} - {{a.name}}</option></select><select v-model="f.default_expense_account_id" class="w-full rounded bg-black p-3 text-white"><option value="">Despesa padrão</option><option v-for="a in resultAccounts" :key="a.id" :value="a.id">{{a.code}} - {{a.name}}</option></select><button class="rounded bg-indigo-600 px-4 py-2 text-white">Salvar fornecedor</button></form></AppLayout></template>
